#include <bits/stdc++.h>using namespace std;#define int long long int#define all(x) x.begin(), x.end() void solve() {    int n, k, p, q; cin >> n >> k >> p >> q;    vector<int> v(n), a(n), b(n), c(n);    for (auto& i : v) cin >> i;    int sm = 0;    for (int i = 0; i < n; i++) {        a[i] = (v[i] % p) % q;        b[i] = (v[i] % q) % p;        c[i] = min(a[i], b[i]);        sm += c[i];    }    int e = 0, f = 0;    for (int i = 0; i < k; i++) e += a[i] - c[i], f += b[i] - c[i];    int mn = sm + min(e, f);    for (int i = k; i < n; i++) {        e -= a[i - k] - c[i - k];        f -= b[i - k] - c[i - k];        e += a[i] - c[i];        f += b[i] - c[i];        mn = min(mn, sm + min(e, f));    }    cout << mn << '\n';}int32_t main() {    ios_base::sync_with_stdio(0); cin.tie(0);    int t = 1; cin >> t;    while (t--) solve();    return 0;}